-- Sembrar control de vacaciones (corre DESPUÉS de agregar las columnas)
update public.employees set vac_anios=15, vac_mes_reseteo=5, vac_dias_base=0, vac_ultimo_reset_anio=(case when 5 <= extract(month from current_date) then extract(year from current_date) else extract(year from current_date)-1 end) where nombre ilike 'Adriana%' and apellido_paterno ilike 'Barrera%';
